import React, { useState } from "react";

const Login = ({ onLogin }) => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showError, setShowError] = useState(false);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setShowError(false);
    setLoading(true);

    try {
      // Replace this with your real backend call
      // Example:
      // const res = await axios.post("/api/login", { email, password });
      // localStorage.setItem("token", res.data.token);
      // onLogin && onLogin(res.data.user);

      // Demo fallback:
      await new Promise((r) => setTimeout(r, 700));
      if (email === "admin@gmail.com" && password === "admin") {
        onLogin && onLogin({ email });
      } else {
        setShowError(true);
      }
    } catch (err) {
      setShowError(true);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="g-auth-bg">
      <div className="g-auth-card">
        <div className="g-auth-logo">
          {/* Optional brand wordmark */}
          <span className="g-dot g-blue" />
          <span className="g-dot g-red" />
          <span className="g-dot g-yellow" />
          <span className="g-dot g-green" />
          <span className="g-brand">NeuroFleetX</span>
        </div>

        <h1 className="g-title">Sign in</h1>
        <p className="g-subtitle">Use your account</p>

        {showError && (
          <div className="g-error">Wrong credentials. Try again.</div>
        )}

        <form onSubmit={handleSubmit} className="g-form">
          <div className="g-field">
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="g-input"
              placeholder="Email"
              autoComplete="username"
              required
              autoFocus
            />
          </div>

          <div className="g-field">
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="g-input"
              placeholder="Password"
              autoComplete="current-password"
              required
            />
          </div>

          <div className="g-actions">
            <button
              type="submit"
              className="g-btn"
              disabled={loading}
              aria-busy={loading}
            >
              {loading ? "Signing in…" : "Sign in"}
            </button>
          </div>
        </form>

        <div className="g-help">
          <a href="#" onClick={(e) => e.preventDefault()}>
            Forgot password?
          </a>
        </div>
      </div>
    </div>
  );
};

export default Login;
